# Implementation Plan: Adding Real-Time Notifications to Existing REST API

## 1. Architecture Overview

### Core Components
- **WebSocket Gateway**: Primary real-time communication layer
- **Notification Service**: Business logic for managing notifications
- **Message Broker**: Queue system for reliable message delivery
- **Notification Store**: Persistence layer for notification history
- **Connection Manager**: WebSocket connection lifecycle management

### Technology Stack
- **WebSocket Implementation**: Socket.IO for cross-browser compatibility
- **Message Broker**: Redis Pub/Sub with Redis Streams for persistence
- **Database**: PostgreSQL for notification storage
- **Caching**: Redis for active connection metadata

## 2. Database Schema

```sql
-- Notifications table
CREATE TABLE notifications (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL,
    type VARCHAR(50) NOT NULL,
    title VARCHAR(255) NOT NULL,
    message TEXT,
    data JSONB,
    is_read BOOLEAN DEFAULT FALSE,
    priority INTEGER DEFAULT 1, -- 1=low, 2=medium, 3=high, 4=urgent
    created_at TIMESTAMP DEFAULT NOW(),
    expires_at TIMESTAMP,
    INDEX idx_user_created (user_id, created_at DESC),
    INDEX idx_user_unread (user_id, is_read) WHERE is_read = FALSE
);

-- User notification preferences
CREATE TABLE notification_preferences (
    user_id UUID PRIMARY KEY,
    email_enabled BOOLEAN DEFAULT TRUE,
    push_enabled BOOLEAN DEFAULT TRUE,
    realtime_enabled BOOLEAN DEFAULT TRUE,
    types_enabled JSONB DEFAULT '{}', -- {"order": true, "message": false}
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Active WebSocket connections
CREATE TABLE active_connections (
    connection_id UUID PRIMARY KEY,
    user_id UUID NOT NULL,
    socket_id VARCHAR(255) NOT NULL,
    server_instance VARCHAR(100) NOT NULL,
    connected_at TIMESTAMP DEFAULT NOW(),
    last_ping TIMESTAMP DEFAULT NOW(),
    INDEX idx_user_connections (user_id)
);
```

## 3. WebSocket Gateway Implementation

```javascript
// websocket-gateway.js
const io = require('socket.io')(server, {
    cors: { origin: process.env.ALLOWED_ORIGINS },
    transports: ['websocket', 'polling']
});

class WebSocketGateway {
    constructor(notificationService, connectionManager) {
        this.notificationService = notificationService;
        this.connectionManager = connectionManager;
        this.setupEventHandlers();
    }

    setupEventHandlers() {
        io.use(this.authenticateSocket.bind(this));

        io.on('connection', async (socket) => {
            const userId = socket.userId;

            // Register connection
            await this.connectionManager.addConnection(userId, socket.id);

            // Join user-specific room
            socket.join(`user:${userId}`);

            // Send pending notifications
            await this.sendPendingNotifications(socket, userId);

            socket.on('mark_read', this.handleMarkRead.bind(this, socket));
            socket.on('disconnect', this.handleDisconnect.bind(this, socket));
        });
    }

    async authenticateSocket(socket, next) {
        try {
            const token = socket.handshake.auth.token;
            const user = await this.validateJWT(token);
            socket.userId = user.id;
            next();
        } catch (error) {
            next(new Error('Authentication failed'));
        }
    }
}
```

## 4. Notification Service

```javascript
// notification-service.js
class NotificationService {
    constructor(db, messageQueue, connectionManager) {
        this.db = db;
        this.messageQueue = messageQueue;
        this.connectionManager = connectionManager;
    }

    async createNotification(userId, notification) {
        // Validate notification data
        const validatedNotification = this.validateNotification(notification);

        // Store in database
        const savedNotification = await this.db.notifications.create({
            user_id: userId,
            ...validatedNotification
        });

        // Check user preferences
        const preferences = await this.getUserPreferences(userId);
        if (!preferences.realtime_enabled) return savedNotification;

        // Queue for real-time delivery
        await this.messageQueue.publish('notifications', {
            type: 'NEW_NOTIFICATION',
            userId,
            notification: savedNotification
        });

        return savedNotification;
    }

    async broadcastToUser(userId, notification) {
        const connections = await this.connectionManager.getUserConnections(userId);

        for (const connection of connections) {
            io.to(connection.socketId).emit('notification', {
                id: notification.id,
                type: notification.type,
                title: notification.title,
                message: notification.message,
                data: notification.data,
                priority: notification.priority,
                timestamp: notification.created_at
            });
        }
    }
}
```

## 5. REST API Integration

