## 6. Message Queue Integration

```javascript
// message-queue.js
class MessageQueue {
    constructor() {
        this.redis = new Redis(process.env.REDIS_URL);
        this.setupConsumers();
    }

    async publish(channel, message) {
        await this.redis.xadd(
            `stream:${channel}`,
            '*',
            'data',
            JSON.stringify(message)
        );
    }

    setupConsumers() {
        this.consumeNotifications();
    }

    async consumeNotifications() {
        while (true) {
            try {
                const messages = await this.redis.xread(
                    'BLOCK', 1000,
                    'STREAMS', 'stream:notifications', '$'
                );

                for (const [stream, entries] of messages || []) {
                    for (const [id, fields] of entries) {
                        const data = JSON.parse(fields[1]);
                        await this.handleNotificationMessage(data);
                    }
                }
            } catch (error) {
                console.error('Queue consumer error:', error);
                await new Promise(resolve => setTimeout(resolve, 5000));
            }
        }
    }
}
```

## 7. Connection Manager

```javascript
// connection-manager.js
class ConnectionManager {
    constructor(db, redis) {
        this.db = db;
        this.redis = redis;
    }

    async addConnection(userId, socketId) {
        const connectionId = uuidv4();

        // Store in database
        await this.db.active_connections.create({
            connection_id: connectionId,
            user_id: userId,
            socket_id: socketId,
            server_instance: process.env.SERVER_INSTANCE_ID
        });

        // Cache in Redis
        await this.redis.hset(
            `connections:${userId}`,
            socketId,
            JSON.stringify({ connectionId, connectedAt: Date.now() })
        );

        return connectionId;
    }

    async removeConnection(userId, socketId) {
        await this.redis.hdel(`connections:${userId}`, socketId);
        await this.db.active_connections.delete({
            socket_id: socketId,
            user_id: userId
        });
    }

    async getUserConnections(userId) {
        const connections = await this.redis.hgetall(`connections:${userId}`);
        return Object.entries(connections).map(([socketId, data]) => ({
            socketId,
            ...JSON.parse(data)
        }));
    }
}
```

