class MessageQueue {
    constructor() {
        this.redis = new Redis(process.env.REDIS_URL);
        this.consumerGroup = 'notification-processors';
        this.consumerName = `${process.env.SERVER_INSTANCE_ID}-${process.pid}`;
        this.setupConsumerGroup();
    }

    async setupConsumerGroup() {
        try {
            await this.redis.xgroup('CREATE', 'stream:notifications', this.consumerGroup, '0', 'MKSTREAM');
        } catch (error) {
            // Group already exists
        }
        this.startConsumer();
    }

    startConsumer() {
        setImmediate(async () => {
            try {
                const messages = await this.redis.xreadgroup(
                    'GROUP', this.consumerGroup, this.consumerName,
                    'COUNT', 10,
                    'BLOCK', 5000,
                    'STREAMS', 'stream:notifications', '>'
                );

                if (messages?.length) {
                    await this.processMessages(messages);
                }
            } catch (error) {
                console.error('Consumer error:', error);
            }

            // Schedule next iteration
