                await this.directNotificationDelivery(userId, savedNotification);
            }

            return savedNotification;
        } catch (dbError) {
            // If database fails, at least try to send real-time notification
            console.error('Database error, sending ephemeral notification:', dbError);
            await this.directNotificationDelivery(userId, notification);
            throw dbError;
        }
